const results = $.steps.searchBusinesses.response.results || $.steps.searchBusinesses.response.data || [];
const businesses = results.slice(0, 8).map((r, i) => ({
  index: i + 1,
  url: r.url || '',
  title: r.title || 'Business ' + (i + 1),
  snippet: (r.text || '').slice(0, 300)
})).filter(b => b.url.length > 0);

return { businesses, businessCount: businesses.length, location: $.input.location || '' };

const businesses = $.steps.extractUrls.output.businesses;
const iterations = $.steps.scrapeBusinessSites.response.iterations || [];
let compiled = '';
let successCount = 0;

iterations.forEach((iter, i) => {
  const biz = businesses[i] || { url: 'Unknown', title: 'Unknown' };
  const resp = (iter.scrapeSite && iter.scrapeSite.response && iter.scrapeSite.response.data) ? iter.scrapeSite.response.data : null;

  compiled += '=== BUSINESS ' + (i + 1) + ': ' + biz.title + ' ===\n';
  compiled += 'URL: ' + biz.url + '\n';
  compiled += 'Search Snippet: ' + (biz.snippet || '') + '\n';

  if (resp && resp.markdown) {
    successCount++;
    compiled += 'Website Content:\n' + resp.markdown.slice(0, 3000) + '\n\n';
  } else {
    compiled += 'Website: Could not scrape\n\n';
  }
});

return { compiled, successCount, totalBusinesses: businesses.length };

const d = $.steps.compileBusinessData.output;
const bizType = $.input.businessType;
const location = $.input.location;

let prompt = 'You are a lead generation specialist. Extract structured contact and business information from the following scraped business websites.\n\n';
prompt += 'BUSINESS TYPE: ' + bizType + '\n';
prompt += 'TARGET LOCATION: ' + location + '\n';
prompt += 'BUSINESSES SCRAPED: ' + d.successCount + '/' + d.totalBusinesses + '\n\n';
prompt += 'BUSINESS DATA:\n' + d.compiled + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Extract all contact information: business name, phone, email, address, website\n';
prompt += '- Look for owner/manager names if available\n';
prompt += '- Extract business hours if listed\n';
prompt += '- Note the business category/type\n';
prompt += '- Rate lead quality (hot/warm/cold) based on available info\n';
prompt += '- If contact info is missing, mark as "Not found"\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "leads": [\n';
prompt += '    {\n';
prompt += '      "businessName": "name",\n';
prompt += '      "phone": "phone or Not found",\n';
prompt += '      "email": "email or Not found",\n';
prompt += '      "address": "full address or Not found",\n';
prompt += '      "website": "url",\n';
prompt += '      "ownerName": "name or Not found",\n';
prompt += '      "businessHours": "hours or Not found",\n';
prompt += '      "category": "business category",\n';
prompt += '      "leadQuality": "hot|warm|cold",\n';
prompt += '      "notes": "any additional relevant info"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "totalLeads": 0,\n';
prompt += '  "hotLeads": 0,\n';
prompt += '  "summary": "brief summary of lead generation results"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiExtract.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { leads: [], totalLeads: 0, hotLeads: 0, summary: raw }; }

const ai = $.steps.parseAI.output;
const leads = ai.leads || [];
const date = new Date().toISOString().split('T')[0];

const sheetData = leads.map((lead, i) => ({
  '#': i + 1,
  'Business Name': lead.businessName || '',
  'Phone': lead.phone || 'Not found',
  'Email': lead.email || 'Not found',
  'Address': lead.address || 'Not found',
  'Website': lead.website || '',
  'Owner/Contact': lead.ownerName || 'Not found',
  'Hours': lead.businessHours || 'Not found',
  'Category': lead.category || '',
  'Lead Quality': lead.leadQuality || 'cold',
  'Notes': lead.notes || ''
}));

return { sheetData, leadCount: leads.length, hotLeads: ai.hotLeads || 0, summary: ai.summary || '', date };

const ai = $.steps.parseAI.output;
const d = $.steps.buildSheetData.output;
const scraped = $.steps.compileBusinessData.output;
const leads = ai.leads || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Business Lead Generation Complete', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Business Type:*\n' + ($.input.businessType || 'N/A') },
  { type: 'mrkdwn', text: '*Location:*\n' + ($.input.location || 'N/A') }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Sites Scraped:*\n' + scraped.successCount + '/' + scraped.totalBusinesses },
  { type: 'mrkdwn', text: '*Leads Found:*\n' + d.leadCount },
  { type: 'mrkdwn', text: '*Hot Leads:*\n' + d.hotLeads }
] });

if (d.summary) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:* ' + d.summary } });
}

blocks.push({ type: 'divider' });

const hotLeads = leads.filter(l => l.leadQuality === 'hot');
if (hotLeads.length > 0) {
  let hotText = '*Hot Leads:*\n';
  hotLeads.slice(0, 5).forEach((l, i) => {
    hotText += (i + 1) + '. *' + (l.businessName || 'N/A') + '*';
    if (l.phone !== 'Not found') hotText += ' | ' + l.phone;
    if (l.email !== 'Not found') hotText += ' | ' + l.email;
    hotText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: hotText.slice(0, 1800) } });
}

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':chart_with_upwards_trend: All ' + d.leadCount + ' leads saved to Google Sheets: *' + ($.input.sheetTitle || 'Business Leads') + '*' } });

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI + Google Sheets | One CLI' }] });

const fallback = 'Lead Gen: ' + d.leadCount + ' leads (' + d.hotLeads + ' hot) for ' + ($.input.businessType || '') + ' in ' + ($.input.location || '');
return { blocks, fallback };
